// Sankofa brand asset for the iOS Pulse renderer.
//
// Mirrors @sankofa/pulse src/brand.ts (Web SDK) so the "Powered by
// Sankofa" attribution row in mobile surveys uses the exact same
// icon as the web SDK and the dashboard Theme tab preview. Drift
// between platforms breaks the WYSIWYG promise.
//
// Source version: 2026-05.

import Foundation

internal enum SankofaPulseBrand {
    /// Base64-encoded WebP. Decode at first render time and cache
    /// the resulting UIImage / Image for the lifetime of the app.
    static let iconBase64 =
      ""

    static let attributionURL = URL(string: "https://sankofa.dev?utm_source=pulse_survey")!

    static let attributionLabel = "Powered by Sankofa"
}
